return [{
  json: {
    mode: 'altruistic',  // 'selfish' or 'altruistic'
    prompt_paradigm: 'few-shot-cot',  // 'zero-shot', 'cot', 'few-shot', 'few-shot-cot'
    description: 'altruistic = minimize PTO costs, selfish = maximize aggregator revenue'
  }
}];

const raw = $('Evaluate & Adapt').first().json;
const result = raw.output ?? raw;

const MAX_RERUNS = 3;
const rerun_count = result.rerun_count ?? 0;

// Best state pass-through
const best_state = {
  best_selfish_revenue:  result.best_selfish_revenue  ?? null,
  best_altruistic_cost:  result.best_altruistic_cost  ?? null,
  best_buy_multipliers:  result.best_buy_multipliers  ?? null,
  best_sell_multipliers: result.best_sell_multipliers ?? null,
  best_mode:             result.best_mode             ?? null,
};

const safeDefaults = {
  selfish:    { buy: Array(48).fill(1.20), sell: Array(48).fill(0.55) },
  altruistic: { buy: Array(48).fill(1.03), sell: Array(48).fill(0.90) },
};
const mode = result.best_mode || 'altruistic';

if (rerun_count >= MAX_RERUNS) {
  return [{
    json: {
      outcome: 'accept',
      reasoning: `Rerun cap of ${MAX_RERUNS} reached. Accepting best result found.`,
      adjusted_guidance: result.adjusted_guidance || {
        buy_multipliers:  safeDefaults[mode].buy,
        sell_multipliers: safeDefaults[mode].sell,
        mode:             mode,
      },
      rerun_count: 0,
      ...best_state,
    }
  }];
}

return [{
  json: {
    outcome:           result.outcome,
    reasoning:         result.reasoning,
    adjusted_guidance: result.adjusted_guidance || {
      buy_multipliers:  safeDefaults[mode].buy,
      sell_multipliers: safeDefaults[mode].sell,
      mode:             mode,
    },
    rerun_count: result.outcome === 'accept' ? 0 : rerun_count + 1,
    ...best_state,
  }
}];

const allInputs = $input.all();
// Find data item (has 'input' key)
const dataItem = allInputs.find(item => item.json.input) || allInputs[0];
const data = dataItem.json;

// ── Mode and prompt paradigm (passed from Workflow Config) ────────────────────
let mode = 'altruistic';
let promptParadigm = 'zero-shot';
try {
  mode = $('Workflow Config').first().json.mode || 'altruistic';
  promptParadigm = $('Workflow Config').first().json.prompt_paradigm || 'zero-shot';
} catch(e) {
  mode = 'altruistic';
  promptParadigm = 'zero-shot';
}

// ── Grid prices ───────────────────────────────────────────────────────────────
const prices = data.input?.prices || [];
const spotPrices = prices.map(p => p.spot_market).filter(p => p != null);
if (spotPrices.length === 0) {
  throw new Error('No spot market prices found in input');
}

const T = spotPrices.length;
const avgPrice   = spotPrices.reduce((a, b) => a + b, 0) / T;
const minPrice   = Math.min(...spotPrices);
const maxPrice   = Math.max(...spotPrices);
const priceSpread = maxPrice - minPrice;

// ── Lowest and highest price timesteps ───────────────────────────────────────
const lowestPriceTimestep  = spotPrices.indexOf(minPrice);
const highestPriceTimestep = spotPrices.indexOf(maxPrice);

// ── Period boundaries (matching app.py defaults) ──────────────────────────────
const b1 = Math.floor(T / 3);
const b2 = Math.floor(T * 2 / 3);

const period1Prices = spotPrices.slice(0, b1);
const period2Prices = spotPrices.slice(b1, b2);
const period3Prices = spotPrices.slice(b2);

const avgPeriod1 = (period1Prices.reduce((a, b) => a + b, 0) / period1Prices.length).toFixed(6);
const avgPeriod2 = (period2Prices.reduce((a, b) => a + b, 0) / period2Prices.length).toFixed(6);
const avgPeriod3 = (period3Prices.reduce((a, b) => a + b, 0) / period3Prices.length).toFixed(6);

const minPeriod1 = Math.min(...period1Prices).toFixed(6);
const minPeriod2 = Math.min(...period2Prices).toFixed(6);
const minPeriod3 = Math.min(...period3Prices).toFixed(6);

const maxPeriod1 = Math.max(...period1Prices).toFixed(6);
const maxPeriod2 = Math.max(...period2Prices).toFixed(6);
const maxPeriod3 = Math.max(...period3Prices).toFixed(6);

const spreadPeriod1 = (Math.max(...period1Prices) - Math.min(...period1Prices)).toFixed(6);
const spreadPeriod2 = (Math.max(...period2Prices) - Math.min(...period2Prices)).toFixed(6);
const spreadPeriod3 = (Math.max(...period3Prices) - Math.min(...period3Prices)).toFixed(6);

// ── Identify lowest and highest price periods ─────────────────────────────────
const periodAvgs = [
  parseFloat(avgPeriod1),
  parseFloat(avgPeriod2),
  parseFloat(avgPeriod3),
];
const lowestPricePeriod  = periodAvgs.indexOf(Math.min(...periodAvgs)) + 1;
const highestPricePeriod = periodAvgs.indexOf(Math.max(...periodAvgs)) + 1;

// ── Final context ─────────────────────────────────────────────────────────────
const context = {
  mode: mode,
  prompt_paradigm: promptParadigm,
  period_boundaries: [b1, b2, T],
  T_steps: T,
  avg_grid_price: avgPrice.toFixed(6),
  spot_prices: spotPrices,
  price_summary: {
    avg:    avgPrice.toFixed(6),
    min:    minPrice.toFixed(6),
    max:    maxPrice.toFixed(6),
    spread: priceSpread.toFixed(6),
    period_1_avg: avgPeriod1,
    period_2_avg: avgPeriod2,
    period_3_avg: avgPeriod3,
    period_1_min: minPeriod1,
    period_2_min: minPeriod2,
    period_3_min: minPeriod3,
    period_1_max: maxPeriod1,
    period_2_max: maxPeriod2,
    period_3_max: maxPeriod3,
    period_1_spread: spreadPeriod1,
    period_2_spread: spreadPeriod2,
    period_3_spread: spreadPeriod3,
    lowest_price_period:   lowestPricePeriod,
    highest_price_period:  highestPricePeriod,
    lowest_price_timestep:  lowestPriceTimestep,
    highest_price_timestep: highestPriceTimestep,
  },
};

return [{ json: { context, data: data.input } }];

const buses              = $('Fetch Buses').all().map(i => i.json);
const chargers           = $('Fetch Chargers').all().map(i => i.json);
const trip_time          = $('Fetch Trips').all().map(i => i.json);
const prices             = $('Fetch Prices').all().map(i => i.json);
const settings           = $("Fetch Setting").all().map(i => i.json);


return [{ json: { buses, chargers, trip_time, prices, settings } }];

const raw = $input.first().json;

function toSnakeCase(str) {
  return String(str)
    .toLowerCase()
    .replace(/[()\/]/g, '')       // remove brackets, slashes
    .replace(/[^a-z0-9\s_]/g, '') // remove remaining special chars
    .trim()
    .replace(/\s+/g, '_');
}

function processTable(rows) {
  if (!rows || rows.length === 0) return [];

  return rows
    .map(row => {
      const normalized = {};
      for (const [key, val] of Object.entries(row)) {
        if (key === null || key === undefined || key === '') continue;
        const newKey = toSnakeCase(key);
        // Convert to number if possible, else keep as-is
        normalized[newKey] = (val !== null && val !== '' && !isNaN(val)) 
          ? Number(val) 
          : val;
      }
      return normalized;
    })
    .filter(row =>
      // Remove rows where all values are null/empty
      Object.values(row).some(v => v !== null && v !== undefined && v !== '')
    );
}

const output = {
  buses:              processTable(raw.buses),
  chargers:           processTable(raw.chargers),
  trip_time:          processTable(raw.trip_time),
  prices:             processTable(raw.prices),
  settings:           processTable(raw.settings),
};

return [{ json: { input: output } }];

const preprocessed = $('Preprocess Inputs').first().json;
const llmOutput = $('LLM Decision Agent').first().json;

let priceGuidance;
let rerunCount = 0;

try {
  const evalOutput = $('Check Rerun Cap').first().json;
  if (evalOutput && evalOutput.outcome === 'rerun') {
    priceGuidance = evalOutput.adjusted_guidance;
    rerunCount = evalOutput.rerun_count;
  }
} catch(e) {}

if (!priceGuidance) {
  priceGuidance = llmOutput.output?.price_guidance || {
    buy_multipliers:  [1.10, 1.15, 1.10],
    sell_multipliers: [0.80, 0.85, 0.80],
    period_boundaries: [32, 64, 96]
  };
}

let disturbances = [];
try {
  disturbances = $('Build LLM Context').first().json.context.disturbances.active || [];
} catch(e) {}

return [{
  json: {
    input: preprocessed.input,
    price_guidance: priceGuidance,
    disturbances: disturbances,
    rerun_count: rerunCount,
    max_iter: 1
  }
}];

const result = $('Poll Job Result').first().json;

let rerun_count = 0;
try {
  rerun_count = $('Check Rerun Cap').first().json.rerun_count ?? 0;
} catch(e) {}

return [{
  json: {
    status:                  result.status,
    is_mock:                 result.is_mock,
    mock_reason:             result.mock_reason ?? null,
    // Price settings
    buy_multipliers:         result.buy_multipliers,
    sell_multipliers:        result.sell_multipliers,
    period_boundaries:       result.period_boundaries,
    avg_grid_price:          result.avg_grid_price,
    avg_buy_price:           result.avg_buy_price,
    avg_sell_price:          result.avg_sell_price,
    price_guidance_used:     result.price_guidance_used,
    // Economic outcomes
    pto_daily_cost:          result.pto_daily_cost,
    aggregator_revenue:      result.aggregator_revenue,
    aggregator_buy_margin:   result.aggregator_buy_margin,
    aggregator_sell_margin:  result.aggregator_sell_margin,
    total_buy_cost:          result.total_buy_cost,
    total_sell_revenue:      result.total_sell_revenue,
    total_degradation:       result.total_degradation ?? null,
    total_kwh_sold:          result.total_kwh_sold,
    total_kwh_bought:        result.total_kwh_bought,
    // Time series
    w_buy:                   result.w_buy,
    w_sell:                  result.w_sell,
    energy:                  result.energy,
    // Pass-through
    rerun_count:             rerun_count,
    disturbances_applied:    [],
  }
}];

