const result = $('Extract Result').first().json;

let mode = 'altruistic';
try {
  mode = $('Workflow Config').first().json.mode || 'altruistic';
} catch(e) {
  try {
    mode = $('Build LLM Context').first().json.context.mode || 'altruistic';
  } catch(e2) { mode = 'altruistic'; }
}

// Selfish:    maximize aggregator_revenue
// Altruistic: minimize pto_daily_cost (negate so higher = better for comparison)
const aggregator_profit = mode === 'selfish'
  ? (result.aggregator_revenue ?? 0)
  : -(result.pto_daily_cost ?? 0);

return [{
  json: {
    ...result,
    aggregator_profit: aggregator_profit,
    mode: mode,
  }
}];

let metrics = {};
try { metrics = $('Compute Metrics').first().json; } catch(e) {
  try { metrics = $('Extract Result').first().json; } catch(e2) {}
}

// Load best from previous loop iteration via Check Rerun Cap
let prev = {};
try { prev = $('Check Rerun Cap').first().json; } catch(e) {}

const current_mode = metrics.mode || 'altruistic';

// ── Rerun count — passed through from Check Rerun Cap ────────────────────────
const rerun_count = prev.rerun_count ?? 0;

// ── Best known state ──────────────────────────────────────────────────────────
const current_best_selfish    = parseFloat(prev.best_selfish_revenue) || -Infinity;
const current_best_altruistic = parseFloat(prev.best_altruistic_cost) ||  Infinity;

let best_selfish_revenue  = isFinite(current_best_selfish)    ? current_best_selfish    : -Infinity;
let best_altruistic_cost  = isFinite(current_best_altruistic) ? current_best_altruistic :  Infinity;
let best_buy_mults        = prev.best_buy_multipliers  ?? null;
let best_sell_mults       = prev.best_sell_multipliers ?? null;
let best_mode             = prev.best_mode             ?? current_mode;
let is_new_best           = false;

// ── Update best if improved ───────────────────────────────────────────────────
if (!metrics.is_mock) {
  if (current_mode === 'selfish' &&
      metrics.aggregator_revenue !== null &&
      metrics.aggregator_revenue !== undefined &&
      isFinite(parseFloat(metrics.aggregator_revenue)) &&
      parseFloat(metrics.aggregator_revenue) > best_selfish_revenue) {
    best_selfish_revenue = parseFloat(metrics.aggregator_revenue);
    best_buy_mults       = JSON.stringify(metrics.buy_multipliers  || Array(48).fill(1.20));
    best_sell_mults      = JSON.stringify(metrics.sell_multipliers || Array(48).fill(0.55));
    best_mode            = 'selfish';
    is_new_best          = true;
  }
  if (current_mode === 'altruistic' &&
      metrics.pto_daily_cost !== null &&
      metrics.pto_daily_cost !== undefined &&
      isFinite(parseFloat(metrics.pto_daily_cost)) &&
      parseFloat(metrics.pto_daily_cost) < best_altruistic_cost) {
    best_altruistic_cost = parseFloat(metrics.pto_daily_cost);
    best_buy_mults       = JSON.stringify(metrics.buy_multipliers  || Array(48).fill(1.03));
    best_sell_mults      = JSON.stringify(metrics.sell_multipliers || Array(48).fill(0.90));
    best_mode            = 'altruistic';
    is_new_best          = true;
  }
}

return [{
  json: {
    ...metrics,
    best_selfish_revenue:  best_selfish_revenue === -Infinity ? null : best_selfish_revenue,
    best_altruistic_cost:  best_altruistic_cost ===  Infinity ? null : best_altruistic_cost,
    best_buy_multipliers:  best_buy_mults,
    best_sell_multipliers: best_sell_mults,
    best_mode:             best_mode,
    is_new_best:           is_new_best,
    rerun_count:           rerun_count,
  }
}];

const decision = $('LLM Decision Agent').first().json || {};
const action = decision.action || 'unknown';
const reasoning = decision.reasoning || 'No reasoning provided';
const confidence = decision.confidence || 0;
const price_guidance = decision.price_guidance || {};

let upper_bound = null, lower_bound = null, is_mock = null;
let pho_plus = null, pho_minus = null;
let energy = null, w_buy = null, w_sell = null;
let pto_daily_cost = null, aggregator_revenue = null;
let buy_multipliers = null, sell_multipliers = null, avg_grid_price = null;

try {
  const result = $('Extract Result').first()?.json || {};
  upper_bound       = result.upper_bound       ?? null;
  lower_bound       = result.lower_bound       ?? null;
  is_mock           = result.is_mock           ?? null;
  pho_plus          = result.pho_plus?.[0]     ?? null;
  pho_minus         = result.pho_minus?.[0]    ?? null;
  energy            = result.energy            ?? null;
  w_buy             = result.w_buy             ?? null;
  w_sell            = result.w_sell            ?? null;
  pto_daily_cost    = result.pto_daily_cost    ?? null;
  aggregator_revenue= result.aggregator_revenue?? null;
  buy_multipliers   = result.buy_multipliers   ?? null;
  sell_multipliers  = result.sell_multipliers  ?? null;
  avg_grid_price    = result.avg_grid_price    ?? null;
} catch(e) {}

const context = $('Build LLM Context').first().json?.context || {};
const mode                   = context.mode                          ?? null;
const disturbances_count     = context.disturbances?.count          ?? 0;
const has_severe_disturbance = context.disturbances?.has_severe     ?? false;
const price_avg              = context.price_summary?.average       ?? null;
const price_change_pct       = context.price_summary?.change_pct   ?? null;
const hours_since_last_opt   = context.hours_since_last_optimization?? null;

// --- Day-ahead summary row (single row, overwrites daily) ---
const today = new Date().toISOString().slice(0, 10);
const day_ahead_summary = {
  date:               today,
  mode,
  pto_daily_cost,
  aggregator_revenue,
  buy_multipliers:    JSON.stringify(buy_multipliers),
  sell_multipliers:   JSON.stringify(sell_multipliers),
  avg_grid_price
};

// --- Day-ahead plan rows (48 rows, one per timestep) ---
const day_ahead_plan = [];
for (let t = 0; t < 48; t++) {
  const row = {
    timestep: t,
    w_buy:    w_buy?.[t]  ?? null,
    w_sell:   w_sell?.[t] ?? null,
  };
  for (let b = 0; b < 8; b++) {
    row[`bus_${b + 1}_kwh`] = energy?.[b]?.[t] ?? null;
  }
  day_ahead_plan.push(row);
}

// --- Existing summary string ---
let summary = `Decision: ${action.toUpperCase()}\nReasoning: ${reasoning}\nConfidence: ${(confidence * 100).toFixed(0)}%\n`;
summary += `\nPrice Guidance:\n- X_avg: ${price_guidance.X_avg}\n- Mi_avg: ${price_guidance.Mi_avg}\n- Delta: ${price_guidance.delta}`;
if (action === 'optimize') {
  summary += `\nOptimization Results:\n- Upper Bound: ${upper_bound}\n- Lower Bound: ${lower_bound}\n- Is Mock: ${is_mock}`;
}

return [{ json: {
  summary,
  action,
  reasoning,
  confidence,
  mode,
  disturbances_count,
  has_severe_disturbance,
  price_avg,
  price_change_pct,
  hours_since_last_opt,
  price_guidance_X_avg:  price_guidance.X_avg  ?? null,
  price_guidance_Mi_avg: price_guidance.Mi_avg ?? null,
  price_guidance_delta:  price_guidance.delta  ?? null,
  upper_bound,
  lower_bound,
  is_mock,
  pho_plus,
  pho_minus,
  day_ahead_summary,   // single object → Sheet 1
  day_ahead_plan,      // array of 48 → Sheet 2
  timestamp: new Date().toISOString()
} }];

const agentOutput = $input.first().json;

// n8n stores LLM usage in different places depending on version
const usage = agentOutput.tokenUsage 
  || agentOutput.tokenUsageEstimate 
  || agentOutput.llmOutput?.tokenUsage
  || agentOutput.llmOutput?.estimatedTokens
  || {};

return [{
  json: {
    ...agentOutput,
    captured_prompt_tokens: usage.promptTokens ?? usage.prompt_tokens ?? 0,
    captured_completion_tokens: usage.completionTokens ?? usage.completion_tokens ?? 0,
    captured_total_tokens: usage.totalTokens ?? usage.total_tokens ?? 0,
  }
}];

